def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        score = 0.0
        residual = capacity - item
        layers = 5
        for layer in range(layers):
            if residual <= 0:
                score += 12 + layer * 2
            else:
                inverse = 1 / residual
                score += inverse * (1 + layer * 0.5)
            residual *= 0.6
            if residual < item * 0.1:
                score += 5 * (layers - layer)
        if capacity > 3 * item:
            score *= 0.8
        elif capacity > 2 * item:
            score *= 0.9
        elif capacity == 2 * item:
            score *= 1.05
        else:
            score *= 1.2
        count = 0
        temp_residual = capacity
        while temp_residual > item and count < 4:
            if temp_residual - item < item / 2:
                score += 3
            temp_residual -= item / 3
            count += 1
        if score > 150:
            priorities[i] = 150
        elif score < 0:
            priorities[i] = 0
        else:
            priorities[i] = score
    return priorities
